import { Text, View } from 'react-native'
import React, { Component } from 'react'
import { FlatList } from 'react-native-web'

import api from '../Services/api'

export default class App extends Component {
	render() {
		return (
			<View>
				<FlatList />
			</View>
		)
	}
}
